"use strict";(globalThis.webpackChunkmythogen_engine_blog=globalThis.webpackChunkmythogen_engine_blog||[]).push([[6600],{5387(e,t,n){n.r(t),n.d(t,{assets:()=>l,contentTitle:()=>o,default:()=>c,frontMatter:()=>i,metadata:()=>r,toc:()=>h});var s=n(4848),a=n(8453);const i={},o="Chapter 9: A Tale of Two CEOs \u2014 Lisa Su vs. Pat Gelsinger",r={id:"GameVictory/\u7b2c\u4e5d\u7ae0_CEO\u7684\u751f\u6b7b\u6642\u901f_Lisa_Su_vs_Pat_Gelsinger_v2",title:"Chapter 9: A Tale of Two CEOs \u2014 Lisa Su vs. Pat Gelsinger",description:'On December 1, 2024, Pat Gelsinger "retired" from his position as CEO of Intel.',source:"@site/i18n/en/docusaurus-plugin-content-docs/current/GameVictory/\u7b2c\u4e5d\u7ae0_CEO\u7684\u751f\u6b7b\u6642\u901f_Lisa_Su_vs_Pat_Gelsinger_v2.md",sourceDirName:"GameVictory",slug:"/GameVictory/\u7b2c\u4e5d\u7ae0_CEO\u7684\u751f\u6b7b\u6642\u901f_Lisa_Su_vs_Pat_Gelsinger_v2",permalink:"/MythogenEngine/en/docs/GameVictory/\u7b2c\u4e5d\u7ae0_CEO\u7684\u751f\u6b7b\u6642\u901f_Lisa_Su_vs_Pat_Gelsinger_v2",draft:!1,unlisted:!1,tags:[],version:"current",frontMatter:{},sidebar:"docs",previous:{title:"Chapter 8: The Only Arsenal \u2014 TSMC's Ultimate Monopoly",permalink:"/MythogenEngine/en/docs/GameVictory/\u7b2c\u516b\u7ae0_\u552f\u4e00\u7684\u8ecd\u5de5\u5ee0_\u53f0\u7a4d\u96fb\u7684\u7d42\u6975\u58df\u65b7_v2"},next:{title:"Chapter 10: The Last Lifeline \u2014 When the Giants Personally Tear Down Their Own Stress Test Arenas",permalink:"/MythogenEngine/en/docs/GameVictory/\u7b2c\u5341\u7ae0_\u6700\u5f8c\u4e00\u6839\u6551\u547d\u7a3b\u8349_v2"}},l={},h=[{value:"I. The Sleeping Pill",id:"i-the-sleeping-pill",level:2},{value:"II. The One-Stop Shop",id:"ii-the-one-stop-shop",level:2},{value:"III. Freedom at the Bottom",id:"iii-freedom-at-the-bottom",level:2},{value:"IV. The Immovable Empire",id:"iv-the-immovable-empire",level:2},{value:"V. Closing Arguments",id:"v-closing-arguments",level:2},{value:"VI. The Loot is Still Being Divided",id:"vi-the-loot-is-still-being-divided",level:2}];function d(e){const t={em:"em",h1:"h1",h2:"h2",header:"header",hr:"hr",img:"img",p:"p",strong:"strong",...(0,a.R)(),...e.components};return(0,s.jsxs)(s.Fragment,{children:[(0,s.jsx)(t.header,{children:(0,s.jsx)(t.h1,{id:"chapter-9-a-tale-of-two-ceos--lisa-su-vs-pat-gelsinger",children:"Chapter 9: A Tale of Two CEOs \u2014 Lisa Su vs. Pat Gelsinger"})}),"\n",(0,s.jsx)(t.p,{children:'On December 1, 2024, Pat Gelsinger "retired" from his position as CEO of Intel.'}),"\n",(0,s.jsx)(t.p,{children:'"Retired" is the official wording. Everyone in the industry knew the truth: the board of directors gave him two options\u2014walk out yourself, or be pushed out. He chose the former.'}),"\n",(0,s.jsx)(t.p,{children:"Three years prior, Gelsinger returned to Intel with the halo of a savior. He was the youngest vice president in Intel's history, the chief architect of the 80486 processor, and the company's first Chief Technology Officer\u2014a man who had worked at Intel since he was eighteen, whose technical roots went straight to the bone. He had been CEO of VMware for nine years, multiplying the company's market value several times over, and then returned to Intel in February 2021, announcing he would use the IDM 2.0 strategy to rebuild Intel's manufacturing hegemony."}),"\n",(0,s.jsx)(t.p,{children:"He did everything the textbooks say you should do: poured tens of billions of dollars into building new fabs, established Intel Foundry Services to take on external clients, and released an aggressive process roadmap to catch up to TSMC. The direction was absolutely correct."}),"\n",(0,s.jsx)(t.p,{children:"The result: in August 2024, Intel announced the layoff of 15,000 people\u201415% of its total workforce. In December of the same year, Gelsinger was asked to leave. During his tenure, Intel's stock price plummeted from around $55 to just over $20."}),"\n",(0,s.jsx)(t.p,{children:"On the exact same timeline, someone else was doing the exact opposite."}),"\n",(0,s.jsx)(t.p,{children:"On October 8, 2014, Lisa Su took over as CEO of AMD. At the time, AMD's stock price was under $3. The company was saddled with $2.2 billion in debt. Its net loss for the entire year of 2015 was $660 million. Wall Street analysts weren't discussing whether AMD could turn around\u2014they were discussing when AMD would file for bankruptcy."}),"\n",(0,s.jsx)(t.p,{children:"Ten years later, in 2024, AMD's market capitalization briefly surpassed Intel's."}),"\n",(0,s.jsx)(t.p,{children:"Two CEOs. Evenly matched technical backgrounds. One brought a dying company back to life. The other sent a former empire to the intensive care unit."}),"\n",(0,s.jsx)(t.p,{children:"The difference was not in IQ. Not in effort. Not in vision."}),"\n",(0,s.jsx)(t.p,{children:"The difference was in the system."}),"\n",(0,s.jsx)(t.hr,{}),"\n",(0,s.jsx)(t.h2,{id:"i-the-sleeping-pill",children:"I. The Sleeping Pill"}),"\n",(0,s.jsx)(t.p,{children:"The previous chapter discussed TSMC's moat\u2014trust, neutrality, and non-competition with clients. It mentioned how Intel used exclusive rebates in the early 2000s to lock in OEM manufacturers\u2014the brands like Dell, HP, and Lenovo that buy chips, assemble them into branded computers, and sell them to consumers\u2014indirectly accelerating its own decline in manufacturing."}),"\n",(0,s.jsx)(t.p,{children:"But the rebate case was only the first half of the story."}),"\n",(0,s.jsx)(t.p,{children:"In 2009, the European Union handed down a \u20ac1.06 billion fine, and Intel paid AMD a $1.25 billion settlement. Exclusive rebates\u2014\"If you dare buy AMD's chips, I'll slash your subsidies\"\u2014this naked channel bullying, on the surface, stopped."}),"\n",(0,s.jsx)(t.p,{children:"But Intel didn't stop. It just changed the game."}),"\n",(0,s.jsxs)(t.p,{children:["The new game was called ",(0,s.jsx)(t.strong,{children:"MDF\u2014Market Development Funds"}),'. The industry knows it better as the upgraded version of the "Intel Inside" sticker program.']}),"\n",(0,s.jsx)(t.p,{children:'The operation was simple. Intel no longer said, "You are not allowed to buy AMD\'s chips." It said: "If 80% of the laptops you ship this year use Intel CPUs, and you put my sticker on your ads, I will \'sponsor\' you with tens of millions of dollars in advertising fees and R&D subsidies."'}),"\n",(0,s.jsx)(t.p,{children:"What was the difference? The difference was that lawyers couldn't find a flaw. Exclusive rebates are illegal\u2014you are restricting your client's choices. MDF is legal\u2014you are merely \"rewarding\" your client's loyalty. The result was exactly the same: OEMs were locked into Intel's ecosystem. But the method had evolved from mafia protection rackets to legal commercial bundling."}),"\n",(0,s.jsx)(t.p,{children:"Why would OEMs buy into it?"}),"\n",(0,s.jsx)(t.p,{children:"Because their gross margins were too thin."}),"\n",(0,s.jsx)(t.p,{children:"Lenovo, HP, Dell, Acer\u2014the hardware gross margins for the world's top PC brands are usually between 3% and 5%. The MDF subsidies Intel disbursed annually sometimes equaled an OEM's entire net profit for a quarter. Under that kind of financial pressure, what CEO would dare to switch to AMD on a large scale? If they switched, the products might be a bit cheaper, but the moment Intel's MDF was cut, the next quarter's P&L statement would bleed red."}),"\n",(0,s.jsx)(t.p,{children:(0,s.jsx)(t.strong,{children:"MDF wasn't a rebate. MDF was a safety net spread beneath the OEM's profit structure\u2014as long as you obediently used Intel, this net would catch you. The moment you jumped, the net disappeared."})}),"\n",(0,s.jsx)(t.p,{children:"But MDF was only the first layer. Intel had a second, deeper layer of bundling, and almost no one talks about this layer in public."}),"\n",(0,s.jsx)(t.hr,{}),"\n",(0,s.jsx)(t.h2,{id:"ii-the-one-stop-shop",children:"II. The One-Stop Shop"}),"\n",(0,s.jsx)(t.p,{children:"When an OEM wants to develop a new Intel laptop, Intel doesn't just sell them a CPU."}),"\n",(0,s.jsx)(t.p,{children:"Intel sends out a team of engineers\u2014sometimes dozens of them\u2014to station themselves within the OEM's R&D department. This team helps the OEM write most of the BIOS reference code. They help sort out the trickiest power management issues\u2014switching those sleep states in ACPI, fine-tuning the processor's dynamic frequency scaling, the wake-up sequencing of different peripherals. They help tune the thermals\u2014fan curves, power distribution between the CPU and GPU, every detail of keeping temperatures down inside a thin chassis. They even help verify WiFi stability and test Thunderbolt compatibility."}),"\n",(0,s.jsxs)(t.p,{children:["This suite of services has an industry name: ",(0,s.jsx)(t.strong,{children:"Intel Reference Validation Platform"}),'. A more colloquial term is the "One-Stop Shop Solution."']}),"\n",(0,s.jsx)(t.p,{children:"If you are a product manager at Lenovo and you want to release an Intel laptop: Intel sends people to help you write the BIOS, tune the thermals, test the peripherals, and get you the Intel Evo certification\u2014which means Intel will help advertise for you\u2014and then they give you an MDF subsidy on top of that. From R&D to marketing, Intel has essentially paved the entire road for you. Your engineers only need to do the mechanical design and final assembly. The R&D cycle is short, bugs are few, and time-to-market is fast."}),"\n",(0,s.jsx)(t.p,{children:"Now, suppose you want to release an AMD laptop."}),"\n",(0,s.jsx)(t.p,{children:"AMD will give you AGESA\u2014its base firmware initialization code. What AGESA does is allow the CPU cores, memory controller, and basic peripherals to boot. But everything above AGESA\u2014the full implementation of the BIOS, the fine-tuning of power management, the validation of the thermal design\u2014your engineers have to do it themselves."}),"\n",(0,s.jsx)(t.p,{children:"AMD did not have a customer support team on Intel's scale. It didn't have the resources to station dozens of people in your R&D department to help you clean up edge cases in the BIOS. Nor did it have a marketing certification program equivalent to Intel Evo\u2014at least not in the early Ryzen era."}),"\n",(0,s.jsx)(t.p,{children:(0,s.jsx)(t.strong,{children:"Releasing an Intel machine meant low R&D costs, a short cycle, few bugs, and subsidies. Releasing an AMD machine meant using double the R&D resources, with no subsidies."})}),"\n",(0,s.jsx)(t.p,{children:"Business is business. Naturally, the OEM's BIOS and thermal teams would lean entirely toward Intel. Not because Intel threatened them. It was because Intel made their lives too easy."}),"\n",(0,s.jsxs)(t.p,{children:["This was Intel's true moat in the PC era. It wasn't having the best technology\u2014as Chapter 8 noted, Intel's process was overtaken by TSMC starting in 2018. ",(0,s.jsx)(t.strong,{children:"It was having the most attentive service."})," MDF bound the OEM's financial reports; the one-stop shop bound the OEM's engineering teams. With two ropes tied together, even if Intel's CPU performance fell behind, OEMs wouldn't dare jump ship on a massive scale."]}),"\n",(0,s.jsx)(t.p,{children:"But this moat had a fatal side effect."}),"\n",(0,s.jsx)(t.p,{children:"It was a sleeping pill."}),"\n",(0,s.jsxs)(t.p,{children:['When Intel realized that as long as it disbursed tens of millions in MDF to Lenovo and HP every year and sent a team of engineers to help them sort out the low-level firmware, the OEMs would obediently release Intel laptops\u2014the high of "locking down the channel" was too easy. It was too comfortable. It created a fatal illusion among Intel\'s upper management: ',(0,s.jsx)(t.strong,{children:'"Even if our process falls behind a little, we can still win by relying on the channel and subsidies."'})]}),"\n",(0,s.jsx)(t.p,{children:"In 2014, Intel's 14nm process entered mass production. According to the original plan, 10nm was supposed to follow in 2016."}),"\n",(0,s.jsx)(t.p,{children:"It didn't."}),"\n",(0,s.jsx)(t.p,{children:"10nm ran into severe difficulties. Delayed in 2016. Delayed in 2017. Delayed in 2018. Intel's desktop processors stayed stuck on 14nm for five years\u2014mockingly referred to by the industry as \"14nm+++\". During those five years, TSMC went from 16nm to 7nm and then to 5nm. Intel's process advantage\u2014the core moat the company had maintained for over twenty years\u2014officially flipped in 2018."}),"\n",(0,s.jsx)(t.p,{children:"But Intel's financials didn't collapse."}),"\n",(0,s.jsx)(t.p,{children:"Because OEMs were bound by MDF and the one-stop shop. Even with Intel's 10nm struggling, OEMs didn't dare switch massively to AMD\u2014switching meant losing Intel's engineering support and marketing subsidies. Intel's market share declined at a pace far slower than its technological decline."}),"\n",(0,s.jsxs)(t.p,{children:[(0,s.jsx)(t.strong,{children:"This is the most dangerous state to be in."})," A company's technology is already declining, but channel control makes its financials look fine\u2014like a heart attack patient who just finished a half-marathon because adrenaline and painkillers kept him from feeling the pain. He thinks he can still run. The audience thinks he's still in the lead."]}),"\n",(0,s.jsx)(t.p,{children:"But the heart is already broken."}),"\n",(0,s.jsx)(t.hr,{}),"\n",(0,s.jsx)(t.h2,{id:"iii-freedom-at-the-bottom",children:"III. Freedom at the Bottom"}),"\n",(0,s.jsx)(t.p,{children:"In October 2014, when Lisa Su sat in the CEO chair at AMD, she wasn't facing a sleeping pill. She was facing a critical condition notice."}),"\n",(0,s.jsx)(t.p,{children:"Stock price under $3. Debt of $2.2 billion. Annual losses exceeding $600 million. The fabs had already been spun off in 2009 (GlobalFoundries)\u2014forced out because Intel's rebate war made them unaffordable to keep. The CPU business was crushed by Intel\u2014AMD's Bulldozer architecture was an acknowledged technical disaster, its IPC performance trailing far behind Intel's Haswell. The GPU business was suppressed by NVIDIA. Wall Street was counting down."}),"\n",(0,s.jsx)(t.p,{children:"But Lisa Su had one thing Pat Gelsinger would never have."}),"\n",(0,s.jsx)(t.p,{children:(0,s.jsx)(t.strong,{children:"She had a fully empowered board of directors that delegated absolute authority."})}),"\n",(0,s.jsx)(t.p,{children:"AMD had reached rock bottom. There was nothing left to lose. The board had no interest groups to protect\u2014because there were no interests left to protect. No Wall Street analysts cared about AMD's gross margin for the next quarter\u2014because everyone had already given up on them."}),"\n",(0,s.jsx)(t.p,{children:"Rock bottom meant freedom."}),"\n",(0,s.jsx)(t.p,{children:"Lisa Su used this freedom to do three things."}),"\n",(0,s.jsx)(t.p,{children:(0,s.jsx)(t.strong,{children:"First: All-in on Zen."})}),"\n",(0,s.jsx)(t.p,{children:"In 2012, before Lisa Su took over as CEO, AMD poached legendary processor architect Jim Keller from Apple. Keller had designed the A4 and A5 chips at Apple\u2014the hearts of the iPhone 4 and iPad 2. Even earlier, he had designed the K8 architecture at AMD\u2014the core of the Athlon 64 that crushed the Intel Pentium 4 in 2003."}),"\n",(0,s.jsx)(t.p,{children:"Keller returned to AMD, bringing with him a completely ground-up architecture concept\u2014codenamed Zen."}),"\n",(0,s.jsx)(t.p,{children:'After taking over, Lisa Su pushed all of the company\'s R&D resources onto Zen. Not just "increasing investment"\u2014she went all-in. She axed distracting product lines and concentrated her limited engineers on a single bet.'}),"\n",(0,s.jsx)(t.p,{children:"On March 2, 2017, the first generation of Ryzen processors launched. The IPC performance of the Zen architecture was a 52% improvement over the previous Bulldozer architecture. Overnight, AMD became a serious contender in the desktop CPU market once again."}),"\n",(0,s.jsx)(t.p,{children:(0,s.jsx)(t.strong,{children:"Second: Bypassing the OEM Quagmire and Going Straight for the Console Market."})}),"\n",(0,s.jsx)(t.p,{children:"This is where Lisa Su's strategic vision was sharpest."}),"\n",(0,s.jsx)(t.p,{children:"She knew one thing very clearly: fighting Intel head-on in the PC laptop market was suicide. AMD didn't have the money to distribute MDF, nor did it have a massive engineering team to help OEMs write BIOS. Intel's one-stop service plus marketing subsidies had the PC OEM's underlying architecture tightly bound. Even if AMD made a better CPU, OEMs wouldn't dare adopt it on a massive scale\u2014the switching costs were too high."}),"\n",(0,s.jsx)(t.p,{children:"So she went to a place Intel's MDF and one-stop shop couldn't reach."}),"\n",(0,s.jsx)(t.p,{children:"Sony. Microsoft. Later, Valve."}),"\n",(0,s.jsxs)(t.p,{children:["Console manufacturers are not OEMs. They do not live on Intel's MDF. They have their own BIOS teams\u2014Sony and Microsoft's hardware engineering capabilities are world-class in their own right. They don't need Intel to send people to help write firmware. What they want is something very pure: ",(0,s.jsx)(t.strong,{children:"high-performance silicon"}),". Not one-stop services, not marketing subsidies\u2014just a custom SoC with enough performance, low enough power consumption, and a reasonable price."]}),"\n",(0,s.jsxs)(t.p,{children:["And AMD had a unique advantage that neither Intel nor NVIDIA possessed: ",(0,s.jsx)(t.strong,{children:"It possessed the design capabilities for both high-performance CPUs (x86) and high-performance GPUs (Radeon)."})," It could integrate the CPU and GPU onto the same chip to create a complete SoC. Console manufacturers only had to deal with one supplier."]}),"\n",(0,s.jsx)(t.p,{children:"The PS5 used AMD Zen 2 + RDNA 2. The Xbox Series X used AMD Zen 2 + RDNA 2. The Steam Deck used AMD Zen 2 + RDNA 2. The hearts of all three major gaming platforms came from the exact same company."}),"\n",(0,s.jsx)(t.p,{children:"These semi-custom orders did two things."}),"\n",(0,s.jsx)(t.p,{children:"First, they kept AMD alive. Between 2014 and 2016, when the Zen architecture was not yet on the market, AMD's PC business was bleeding out. It was the console contracts that provided stable, predictable revenue\u2014keeping AMD's engineers fed and allowing R&D for the Zen architecture to continue burning money."}),"\n",(0,s.jsxs)(t.p,{children:["Second, they perfectly bypassed the OEM quagmire laid by Intel. Sony and Microsoft didn't care how much MDF Intel gave Lenovo. They only cared whether the chip could run ",(0,s.jsx)(t.em,{children:"God of War"})," and ",(0,s.jsx)(t.em,{children:"Halo"}),"."]}),"\n",(0,s.jsx)(t.p,{children:(0,s.jsx)(t.strong,{children:"Lisa Su didn't try to pry open Intel's lock. She bypassed the entire wall."})}),"\n",(0,s.jsx)(t.p,{children:(0,s.jsx)(t.strong,{children:"Third: Fully Embracing TSMC."})}),"\n",(0,s.jsx)(t.p,{children:"The end of the previous chapter mentioned this decision. After AMD was forced to spin off its fabs in 2009, it became a fabless company. Lisa Su made a critical choice: hand over all of AMD's most advanced chips to TSMC."}),"\n",(0,s.jsx)(t.p,{children:"This decision didn't look particularly remarkable in 2014. But its long-term effects were devastating\u2014for Intel."}),"\n",(0,s.jsx)(t.p,{children:"Because AMD's chips could henceforth use TSMC's most advanced process nodes. While Intel stagnated on 14nm for five years, AMD's Zen 2 was already using TSMC's 7nm. By Zen 4, AMD was using TSMC's 5nm. Intel's lag in manufacturing process was translated by AMD, leveraging TSMC's power, into product leadership."}),"\n",(0,s.jsx)(t.p,{children:"Freedom at the bottom allowed Lisa Su to do three things that would have been impossible during prosperous times: put all resources on a single bet (Zen), move the battlefield to a place the opponent couldn't reach (consoles), and hand manufacturing over to the best foundry in the world (TSMC)."}),"\n",(0,s.jsx)(t.p,{children:(0,s.jsx)(t.strong,{children:"AMD's resurrection wasn't because Lisa Su was smarter than Pat Gelsinger. It was because rock bottom gave her a system of total delegated authority\u2014while wealth gave Gelsinger an immovable empire."})}),"\n",(0,s.jsx)(t.hr,{}),"\n",(0,s.jsx)(t.h2,{id:"iv-the-immovable-empire",children:"IV. The Immovable Empire"}),"\n",(0,s.jsx)(t.p,{children:"On February 15, 2021, Pat Gelsinger returned to Intel."}),"\n",(0,s.jsx)(t.p,{children:"He saw all the problems. The manufacturing process was trailing TSMC by at least two generations. PC market share was being eaten by AMD. The data center market\u2014Intel's most profitable business\u2014was being squeezed by AMD EPYC and NVIDIA's AI GPUs. The IDM model had turned from a moat into a drag."}),"\n",(0,s.jsx)(t.p,{children:"His prescription\u2014IDM 2.0\u2014was completely correct in its logic: rebuild manufacturing capabilities, open up foundry business to external clients, and use an aggressive process roadmap to catch up to TSMC."}),"\n",(0,s.jsx)(t.p,{children:"The problem was, prescribing the medicine is easy. Making the patient swallow it is hard."}),"\n",(0,s.jsx)(t.p,{children:(0,s.jsx)(t.strong,{children:"The first wall Gelsinger faced: Wall Street."})}),"\n",(0,s.jsx)(t.p,{children:"Building a fab for advanced processes requires capital expenditures in the tens of billions of dollars. The return cycle is at least five to seven years. But Wall Street's time scale is one quarter. At every Intel earnings call, the first question analysts asked was: \"You've spent so much money building fabs, when will we see a return?\" Gelsinger's answer was \"In a few years.\" Wall Street's reaction was to sell off."}),"\n",(0,s.jsx)(t.p,{children:"Lisa Su also faced pressure from Wall Street in 2014. But the difference was: AMD's stock had already fallen to $2, Wall Street had already given up, and no one cared about its gross margin for the next quarter. Gelsinger inherited a company with a $55 stock price\u2014Wall Street had expectations, and with expectations comes the room for disappointment."}),"\n",(0,s.jsx)(t.p,{children:(0,s.jsx)(t.strong,{children:"The second wall Gelsinger faced: Internal Interest Groups."})}),"\n",(0,s.jsx)(t.p,{children:"Intel has over 100,000 employees. The one-stop OEM service team\u2014the massive squad that helped clients write BIOS, tune thermals, and get certifications\u2014was the cornerstone of Intel's channel control. The MDF department managed billions of dollars in marketing budgets annually. The fabs had tens of thousands of manufacturing engineers. Every department had its own budget, its own KPIs, its own political power."}),"\n",(0,s.jsxs)(t.p,{children:["When Gelsinger needed to lay off 15,000 people to save money, he discovered a cruel reality: ",(0,s.jsx)(t.strong,{children:"The people who should be cut couldn't be cut, and the people who could be cut shouldn't be cut."})]}),"\n",(0,s.jsx)(t.p,{children:"That one-stop service team catering to OEMs\u2014could they be cut? Cut them, and OEMs would complain about declining service quality and accelerate their shift to AMD. The MDF department\u2014could it be axed? Axe it, and OEMs lose their subsidies, giving them even more reason to jump on AMD's boat."}),"\n",(0,s.jsx)(t.p,{children:"But Gelsinger had to save money. Wall Street was watching."}),"\n",(0,s.jsx)(t.p,{children:"As a result, the blade swung toward the path of least resistance\u2014engineers without political shelter. Those core engineers quietly researching the next generation architecture, those research teams toiling away on advanced packaging technologies\u2014they didn't have OEM clients speaking up for them, they didn't have marketing budgets to lobby the board. They were laid off."}),"\n",(0,s.jsx)(t.p,{children:(0,s.jsx)(t.strong,{children:"Intel laid off the people it needed most. It kept the people who made it feel the safest but were losing their relevance."})}),"\n",(0,s.jsx)(t.p,{children:"This was not Gelsinger's personal failure. This was a structural dilemma of the system. The one-stop service teams and MDF systems Intel had nurtured for decades\u2014that very mechanism that made OEMs obediently use Intel\u2014had become an immovable institution. It was too big, the interests involved were too deep, and cutting any piece of it would trigger a chain reaction."}),"\n",(0,s.jsx)(t.p,{children:"Lisa Su didn't have to face this problem. AMD in 2014 simply didn't have a one-stop service team\u2014because it was too poor to afford one. It had no MDF budget\u2014because it had no money. It had no interest groups to protect\u2014because everyone was on the same boat, and the boat was sinking."}),"\n",(0,s.jsx)(t.p,{children:(0,s.jsx)(t.strong,{children:"AMD's weakness became its advantage. Only without baggage can you run."})}),"\n",(0,s.jsx)(t.p,{children:"Intel's advantage became its shackles. The baggage was too heavy; it couldn't even move."}),"\n",(0,s.jsx)(t.hr,{}),"\n",(0,s.jsx)(t.h2,{id:"v-closing-arguments",children:"V. Closing Arguments"}),"\n",(0,s.jsx)(t.p,{children:"That pattern appears again. For the seventh time."}),"\n",(0,s.jsx)(t.p,{children:"But this time, the variation is different from the previous ones."}),"\n",(0,s.jsx)(t.p,{children:"Every previous variation\u2014DirectX, Steam, CUDA, TSMC\u2014locked in external people. Microsoft locked in game developers. NVIDIA locked in AI researchers. TSMC locked in global fabless chip companies."}),"\n",(0,s.jsx)(t.p,{children:"This time, the lock was on themselves."}),"\n",(0,s.jsx)(t.p,{children:"Intel used MDF and one-stop services to lock in OEM manufacturers\u2014on the surface, it was locking others, but in reality, it locked itself into a system that it had to continuously supply. OEMs relied on Intel's subsidies and engineering support, and Intel relied on the OEMs' loyalty to maintain market share and financial reports. Both sides were bound to each other, and neither could walk away."}),"\n",(0,s.jsxs)(t.p,{children:["When Intel's process began to fall behind, this mutually binding system didn't sound the alarm\u2014instead, it muted it. ",(0,s.jsx)(t.strong,{children:"OEMs didn't jump ship, so the financials were fine. The financials were fine, so management thought the process lag wasn't fatal. Management thought it wasn't fatal, so the urgency to fix the process was lowered. By the time the problem was too big to ignore, it was five years too late."})]}),"\n",(0,s.jsx)(t.p,{children:"Convenience attracts OEMs \u2192 OEMs are bound by MDF and the one-stop shop \u2192 Intel itself is also bound \u2192 The bundling masks the process decline \u2192 The decline accumulates into a collapse."}),"\n",(0,s.jsx)(t.p,{children:(0,s.jsx)(t.strong,{children:"The one who locked others in back then, ultimately locked themselves in."})}),"\n",(0,s.jsx)(t.p,{children:"Pat Gelsinger was not an incompetent CEO. He was an engineer in the wrong system, holding insufficient real power, trying to pry open an immovable empire. His tragedy wasn't that he couldn't see the problems\u2014he saw all of them. His tragedy was that by the time he returned, MDF and the one-stop shop had been running for twenty years. The interest structures had solidified. To change it, swapping the CEO wasn't enough\u2014it required tearing the whole machine down and rebuilding it. And Wall Street would not give him the time to tear it down and rebuild."}),"\n",(0,s.jsx)(t.p,{children:"Lisa Su's victory wasn't because she was personally superior to Gelsinger either. It was because history gave her a blank chessboard in 2014\u2014Intel's rebate war pushed AMD to the brink of bankruptcy, forced out the fabs, scattered the old system, and stripped away all the baggage. She rebuilt from the ruins, without needing to wrestle with any interest groups."}),"\n",(0,s.jsx)(t.p,{children:(0,s.jsx)(t.strong,{children:"The victors of tech history are not the smartest people. They are the ones in the right system, holding enough real power, who dare to bet everything."})}),"\n",(0,s.jsx)(t.p,{children:"Gelsinger's IQ and technical vision were on par with Lisa Su's. But the company he returned to\u2014an Intel fed by MDF for twenty years\u2014was no longer a company that could be saved by one person."}),"\n",(0,s.jsx)(t.hr,{}),"\n",(0,s.jsx)(t.h2,{id:"vi-the-loot-is-still-being-divided",children:"VI. The Loot is Still Being Divided"}),"\n",(0,s.jsx)(t.p,{children:"In 2025, AMD's Zen architecture simultaneously supplies the three major gaming platforms\u2014PS5, Xbox Series X, and Steam Deck. The hearts of all three major platforms all stem from the chess pieces Lisa Su laid down during AMD's darkest era."}),"\n",(0,s.jsx)(t.p,{children:"If Intel's rebate war hadn't pushed AMD to a dead end, AMD wouldn't have spun off its fabs. If it hadn't spun off its fabs, AMD wouldn't have embraced TSMC. If it hadn't embraced TSMC, AMD's Zen chips wouldn't have used the industry's most advanced processes. If the Zen chips were using GlobalFoundries' trailing-edge processes, they wouldn't have had the performance to crush Intel\u2014and Sony and Microsoft wouldn't have handed the hearts of their major consoles entirely to them."}),"\n",(0,s.jsx)(t.p,{children:"Intel's rebate war \u2192 AMD is pushed to the brink of bankruptcy \u2192 AMD ditches its fabs \u2192 AMD embraces TSMC \u2192 AMD uses TSMC's process to make better chips \u2192 AMD wins the three major console contracts \u2192 The long-term orders from the three major consoles in turn feed TSMC's virtuous cycle."}),"\n",(0,s.jsx)(t.p,{children:(0,s.jsx)(t.strong,{children:"Intel did one thing twenty years ago with billions of dollars in rebates: it forged AMD into a much more dangerous company."})}),"\n",(0,s.jsx)(t.p,{children:"But the bill doesn't just belong to Intel. There's another side to the bill."}),"\n",(0,s.jsx)(t.p,{children:"When Microsoft and Sony handed the hearts of their gaming consoles entirely to AMD, they simultaneously handed something else to AMD\u2014leverage. Leverage at the negotiating table. The hardware lifelines of the two major console giants are held in the hands of the same company."}),"\n",(0,s.jsx)(t.p,{children:'What does this situation turn into when the two giants decide they "no longer want to make games seriously"?'}),"\n",(0,s.jsx)(t.p,{children:"That is the story of the next chapter."}),"\n",(0,s.jsx)(t.p,{children:(0,s.jsx)(t.img,{src:n(1824).A+"",width:"1200",height:"670"})})]})}function c(e={}){const{wrapper:t}={...(0,a.R)(),...e.components};return t?(0,s.jsx)(t,{...e,children:(0,s.jsx)(d,{...e})}):d(e)}},1824(e,t,n){n.d(t,{A:()=>s});const s=n.p+"assets/images/ch09_en-e90c12d256f96a6ed46e7c754229caaa.png"},8453(e,t,n){n.d(t,{R:()=>o,x:()=>r});var s=n(6540);const a={},i=s.createContext(a);function o(e){const t=s.useContext(i);return s.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function r(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(a):e.components||a:o(e.components),s.createElement(i.Provider,{value:t},e.children)}}}]);